rue},\"is_device_based\":false,\"group_name\":\"Treatment\",\"is_experiment_active\":true,\"is_user_in_experiment\":true},\"2433713709\":{\"name\":\"2433713709\",\"rule_id\":\"4KU5vMgln0RfRQV6ltwqKs:100.00:3-4Viuasc1mPfBqiE0jyFfZl\",\"secondary_exposures\":[],\"id_type\":\"userID\",\"value\":{\"webrtc_echo_cancellation_enabled\":false,\"ducking_vad_backend\":\"webrtc\",\"ducking_ducked_remote_volume_db\":-6,\"ducking_duck_minimum_duration_ms\":750,\"ducking_duck_inactive_hold_ms\":300,\"ducking_assistant_echo_gate_render_hold_ms\":500,\"ducking_vad_frame_duration_ms\":10,\"high_confidence_headset_regexes\":[],\"ducking_assistant_echo_gate_minimum_capture_level\":0.04,\"ducking_device_policy\":\"only_speakerphone\",\"ducking_version\":1,\"ducking_ducked_remote_volume\":0.1,\"hardware_echo_cancellation_enabled\":true,\"ducking_vad_aggressiveness\":3,\"ducking_assistant_echo_gate_enabled\":false,\"ducking_restoration_steps\":20,\"ducking_restoration_duration_ms\":1000,\"ducking_assistant_echo_gate_capture_baseline_ratio\":1.8,\"ducking_assistant_echo_gate_capture_to_render_ratio\":0.8,\"ducking_assistant_echo_gate_render_active_threshold\":0.02},\"is_device_based\":false,\"passed\":true},\"1341269548\":{\"name\":\"1341269548\",\"rule_id\":\"default\",\"secondary_exposures\":[{\"gate\":\"295757309\",\"gateValue\":\"false\",\"ruleID\":\"6CYqzLNR69kOtn13xAfiry\"}],\"id_type\":\"userID\",\"value\":{\"kind\":\"social\",\"tempDisabled\":false,\"loginStrategy\":\"existing_user\",\"name\":\"google\",\"enabled\":true},\"is_device_based\":false,\"passed\":false},\"3685705952\":{\"name\":\"3685705952\",\"rule_id\":\"2iM40zAnB3wf9IPQaVNA59-2iM40xVl8LmKQjhUzNRWM7\",\"secondary_exposures\":[],\"id_type\":\"userID\",\"value\":{\"whatsapp\":[\"IN\",\"CO\",\"GB\",\"BR\",\"MX\",\"AR\",\"DE\",\"SE\",\"HU\",\"PH\",\"AU\",\"CZ\",\"IQ\",\"UA\",\"AZ\",\"MA\",\"PL\",\"RO\",\"BE\",\"PT\",\"GR\",\"IT\",\"AT\",\"CL\",\"CH\",\"ES\",\"NL\",\"TR\",\"AE\",\"SG\",\"IL\",\"ZA\",\"KE\",\"PM\",\"GL\",\"NF\",\"AS\",\"MS\",\"NR\",\"NZ\",\"VI\",\"GU\",\"MM\",\"BT\",\"CK\",\"MH\",\"AI\",\"FM\",\"LA\",\"EE\",\"TV\",\"VG\",\"PR\",\"PW\",\"WF\",\"KI\",\"NP\",\"LT\",\"GG\",\"LV\",\"BM\",\"PF\",\"JE\",\"KY\",\"IM\",\"PG\",\"SB\",\"IS\",\"GE\",\"BQ\",\"NC\",\"TC\",\"NI\",\"CW\",\"AW\",\"SV\",\"BS\",\"SX\",\"MD\",\"FJ\",\"TD\",\"WS\",\"ER\",\"TO\",\"SS\",\"FO\",\"ST\",\"NO\",\"VC\",\"SK\",\"KN\",\"FI\",\"DM\",\"LC\",\"TT\",\"AG\",\"GD\",\"SR\",\"BB\",\"GY\",\"BN\",\"GT\",\"SO\",\"NE\",\"RS\",\"CV\",\"DK\",\"BJ\",\"CI\",\"BZ\",\"BA\",\"GQ\",\"GA\",\"DJ\",\"MR\",\"RE\",\"GP\",\"MQ\",\"GF\",\"IE\",\"DO\",\"PA\",\"TN\",\"YT\",\"XK\",\"GM\",\"MK\",\"CG\",\"NA\",\"HR\",\"UY\",\"GI\",\"CR\",\"LR\",\"MW\",\"AD\",\"SC\",\"LS\",\"AL\",\"BH\",\"LI\",\"SZ\",\"LU\",\"CD\",\"OM\",\"MV\",\"BW\",\"CY\",\"MC\",\"KW\",\"PY\",\"MT\",\"TZ\",\"RW\",\"QA\"],\"sms\":[\"US\",\"CA\",\"JP\",\"KR\",\"FR\",\"TW\",\"TH\",\"FK\",\"NU\",\"TL\",\"VU\",\"SM\"]},\"is_device_based\":false,\"passed\":false},\"1977158438\":{\"name\":\"1977158438\",\"rule_id\":\"default\",\"secondary_exposures\":[],\"id_type\":\"userID\",\"value\":{\"system_prompt\":\"The user is asking about an ad shown to them by {advertiser}. Your response must be about the ad shown. They are using the \\\"Ask ChatGPT\\\" feature to get ChatGPT's honest opinion on the product(s) in the advertisement, and in which situations it could be a great fit for them. You should be honest about when you think the product(s) would vs. would not be useful for the user, based on what you know about them.\\n\\nInformation about the ad:\\n{ad}.\\n\\nStructure your response in the following manner:\\n- Briefly describe the type of user, use case, or situation where this ad/product makes sense for the user.\\n- If appropriate, explain any mismatches with the user's stated preferences or goals. That is, where might it fall short for the user (if appropriate)? You don't have to do this for every query, but feel free to list limitations if you think they're pretty relevant.\\n- Give a concise recommendation (e.g., \\\"worth considering,\\\" \\\"probably not ideal,\\\" \\\"good budget option,\\\" \\\"seriously may be a fit,\\\" etc.)\\n\\nGuidelines:\\n- Be honest and practical.\\n- Do not blindly promote the ad.\\n- Avoid harsh or absolute negative language.\\n- Do not invent details not present in the ad.\\n- Focus on fit, not feature lists.\\n- If the mark on relevance is clearly missed, feel free to be funny with it and keep it lighthearted. Do not mock the user or advertiser; keep the humor gentle.\\n\\nKeep it concise, direct, and easy to scan.\\n\\n{conversation}\",\"user_prompt_key\":\"good_option\",\"enable_web_search\":false},\"is_device_based\":false,\"passed\":false},\"3282868491\":{\"name\":\"3282868491\",\"rule_id\":\"2HlyCvw6bnJY8OJCje8QNB:100.00:1\",\"secondary_exposures\":[],\"id_type\":\"userID\",\"value\":{\"short_text\":\"Sources\",\"pill_text\":\"Add Sources\"},\"is_device_based\":false,\"passed\":true},\"193245580\":{\"name\":\"193245580\",\"rule_id\":\"default\",\"secondary_exposures\":[],\"id_type\":\"userID\",\"value\":{\"vscode\":\"vscode:extension/openai.chatgpt\",\"cli\":\"https://developers.openai.com/codex/cli\",\"cursor\":\"cursor:extension/openai.chatgpt\",\"vscodeExtensionAppId\":\"openai.chatgpt\",\"cursorExtensionAppId\":\"openai.chatgpt\",\"windsurf\":\"windsurf:extension/openai.chatgpt\",\"windsurfExtensionAppId\":\"openai.chatgpt\"},\"is_device_based\":false,\"passed\":false},\"2048788910\":{\"name\":\"2048788910\",\"rule_id\":\"default\",\"secondary_exposures\":[],\"id_type\":\"userID\",\"value\":{\"intervalMs\":200,\"enabled\":3},\"is_device_based\":false,\"passed\":false},\"2542357090\":{\"name\":\"2542357090\",\"rule_id\":\"default\",\"secondary_exposures\":[],\"id_type\":\"stableID\",\"value\":{\"default_bootstrap_model_id\":\"gpt-5-5-instant\",\"language_instructions\":{\"id\":\"Response language for the first visible response: natural Indonesian. Use Indonesian for all visible text, including the lead-in and clickable suggestions. Use standard Indonesian punctuation: keep the two opening sentences in one paragraph and end each with a period; an optional emoji may follow the first period. If the user later writes in another language, switch naturally.\",\"hi_latn\":\"Response language for the first visible response: natural Roman Hindi using Latin script only. Translate any English campaign wording before writing. Use Roman Hindi—not English—for every visible element, including the opening, lead-in, and all three clickable suggestions. Common borrowed words are fine, but never write a complete lead-in or suggestion in English. If the user later writes in another language or script, switch naturally.\",\"ja\":\"Response language for the first visible response: natural Japanese. Use Japanese for all visible text, including the lead-in and clickable suggestions. If the user later writes in another language, switch naturally.\",\"pt\":\"Response language for the first visible response: natural Brazilian Portuguese. Use Brazilian Portuguese for all visible text, including the lead-in and clickable suggestions. If the user later writes in another language, switch naturally.\",\"en\":\"Response language for the first visible response: natural English. Use English for all visible text, including the lead-in and clickable suggestions. If the user later writes in another language, switch naturally.\",\"hi\":\"Response language for the first visible response: natural Hindi in Devanagari. Translate any English campaign wording before writing. Use Devanagari Hindi for every visible element—the opening, lead-in, and all three clickable suggestions—and do not copy full English phrases into the response. If the user later writes in another language or script, switch naturally.\",\"es\":\"Response language for the first visible response: natural Spanish. Use Spanish for all visible text, including the lead-in and clickable suggestions. If the user later writes in another language, switch naturally.\"},\"creative_to_campaign\":{\"793910549039\":{\"language_key\":\"ja\",\"campaign_key\":\"restaurant_language_practice\"},\"808801638153\":{\"campaign_key\":\"custom_event_sticker\",\"language_key\":\"hi\"},\"120244941637000182\":{\"campaign_key\":\"reaction_sticker_pack\",\"language_key\":\"en\"},\"120245284408080182\":{\"campaign_key\":\"personal_color_analysis\",\"language_key\":\"hi\"},\"778169782517\":{\"language_key\":\"en\",\"campaign_key\":\"spicy_pani_puri\"},\"778169782547\":{\"campaign_key\":\"spicy_pani_puri\",\"language_key\":\"en\"},\"798449148147\":{\"language_key\":\"hi_latn\",\"campaign_key\":\"cricket_catchup\"},\"798559023059\":{\"campaign_key\":\"cricket_catchup\",\"language_key\":\"en\"},\"798559023035\":{\"campaign_key\":\"cricket_catchup\",\"language_key\":\"en\"},\"120241782769140182\":{\"campaign_key\":\"job_caricature\",\"language_key\":\"en\"},\"778169782544\":{\"language_key\":\"en\",\"campaign_key\":\"spicy_pani_puri\"},\"120245715524740182\":{\"language_key\":\"hi_latn\",\"campaign_key\":\"local_class_finder\"},\"808801747569\":{\"language_key\":\"hi\",\"campaign_key\":\"custom_event_sticker\"},\"801737430134\":{\"language_key\":\"id\",\"campaign_key\":\"bracelet_design\"},\"120245237712380182\":{\"campaign_key\":\"mini_me_world\",\"language_key\":\"hi_latn\"},\"798449063730\":{\"language_key\":\"hi\",\"campaign_key\":\"cricket_catchup\"},\"808836356575\":{\"language_key\":\"hi\",\"campaign_key\":\"custom_event_sticker\"},\"798000225761\":{\"campaign_key\":\"restaurant_language_practice\",\"language_key\":\"ja\"},\"801737502440\":{\"campaign_key\":\"bracelet_design\",\"language_key\":\"id\"},\"120246695158680182\":{\"language_key\":\"es\",\"campaign_key\":\"hair_color_preview\"},\"799747791754\":{\"campaign_key\":\"outdoor_yoga\",\"language_key\":\"id\"},\"798502712140\":{\"language_key\":\"en\",\"campaign_key\":\"cricket_catchup\"},\"120242559330440182\":{\"language_key\":\"en\",\"campaign_key\":\"job_caricature\"},\"798559023047\":{\"campaign_key\":\"cricket_catchup\",\"language_key\":\"en\"},\"1867097550317777\":{\"campaign_key\":\"photo_cartoon\",\"language_key\":\"es\"},\"778169782691\":{\"language_key\":\"hi\",\"campaign_key\":\"spicy_pani_puri\"},\"807118178556\":{\"language_key\":\"ja\",\"campaign_key\":\"image_canvas\"},\"808807097886\":{\"campaign_key\":\"custom_event_sticker\",\"language_key\":\"hi_latn\"},\"120241043845840182\":{\"campaign_key\":\"outfit_transfer\",\"language_key\":\"en\"},\"778169782688\":{\"campaign_key\":\"spicy_pani_puri\",\"language_key\":\"hi\"},\"1867097546221586\":{\"campaign_key\":\"photo_cartoon\",\"language_key\":\"es\"},\"120245610681080182\":{\"campaign_key\":\"photo_comic_story\",\"language_key\":\"id\"},\"799747618960\":{\"campaign_key\":\"vanity_refresh\",\"language_key\":\"id\"},\"120242577223180182\":{\"language_key\":\"en\",\"campaign_key\":\"outfit_transfer\"},\"782461526870\":{\"campaign_key\":\"stylist_workwear\",\"language_key\":\"en\"},\"120245287003550182\":{\"language_key\":\"en\",\"campaign_key\":\"interactive_travel_map\"},\"778169782541\":{\"campaign_key\":\"spicy_pani_puri\",\"language_key\":\"en\"},\"807141203998\":{\"campaign_key\":\"image_canvas\",\"language_key\":\"ja\"},\"120246696337550182\":{\"language_key\":\"es\",\"campaign_key\":\"hair_color_preview\"},\"808801747587\":{\"language_key\":\"hi\",\"campaign_key\":\"custom_event_sticker\"},\"798449063754\":{\"campaign_key\":\"cricket_catchup\",\"language_key\":\"hi\"},\"778150297166\":{\"campaign_key\":\"spicy_pani_puri\",\"language_key\":\"en\"},\"799747800160\":{\"language_key\":\"id\",\"campaign_key\":\"vanity_refresh\"},\"799705222719\":{\"language_key\":\"en\",\"campaign_key\":\"closet_room_refresh\"},\"808801662897\":{\"campaign_key\":\"sketch_to_brand\",\"language_key\":\"hi\"},\"799711141617\":{\"campaign_key\":\"outdoor_yoga\",\"language_key\":\"id\"},\"808801371015\":{\"language_key\":\"hi\",\"campaign_key\":\"custom_event_sticker\"},\"808801662909\":{\"campaign_key\":\"photo_to_headshot\",\"language_key\":\"hi\"},\"798449148159\":{\"campaign_key\":\"cricket_catchup\",\"language_key\":\"hi_latn\"},\"798449063742\":{\"language_key\":\"hi\",\"campaign_key\":\"cricket_catchup\"},\"798449148135\":{\"language_key\":\"hi_latn\",\"campaign_key\":\"cricket_catchup\"},\"120241043845760182\":{\"language_key\":\"en\",\"campaign_key\":\"mini_me_palm\"},\"1867093709812961\":{\"campaign_key\":\"nearby_trip_planning\",\"language_key\":\"ja\"},\"799741745677\":{\"language_key\":\"en\",\"campaign_key\":\"closet_room_refresh\"},\"1867096724761377\":{\"campaign_key\":\"background_cleanup\",\"language_key\":\"es\"},\"120241035841640182\":{\"language_key\":\"pt\",\"campaign_key\":\"room_style_preview\"},\"1867096733187154\":{\"language_key\":\"es\",\"campaign_key\":\"background_cleanup\"}},\"enabled\":true,\"campaigns\":{\"vanity_refresh\":{\"bootstrap_context\":\"You are starting a conversation with a user who arrived from a paid YouTube campaign presented in Indonesian. Treat this as a soft signal of possible interest, never as a fact about the user's identity, home, belongings, budget, location, language preference, or style.\\n\\nCampaign key: vanity_refresh\\nCreative theme: making a vanity or small personal space feel tidier, prettier, and more useful without requiring a full renovation.\\nDemonstrated request: \\\"Beri aku ide untuk membuat meja rias milikku terlihat lebih bagus.\\\"\\nUseful workflow for later turns: work from a supplied photo or description, identify clutter and lighting or layout opportunities, prioritize low-effort changes, reuse what is already there, and optionally visualize a refreshed direction.\\n\\nFor the first visible response:\\n- Make the refresh feel satisfying and achievable, with concrete value around decluttering, styling, lighting, and a visual before-and-after.\\n- Do not assume the user owns a vanity, has a messy space, wants to shop, or prefers the style shown in the creative.\\n- Let the continuation choices offer a quick tidy-and-style plan, a refresh using existing items, and a visual makeover.\\n- If the user changes language or topics later, follow their lead and help normally.\",\"enabled\":true},\"outdoor_yoga\":{\"enabled\":true,\"bootstrap_context\":\"You are starting a conversation with a user who arrived from a paid YouTube campaign presented in Indonesian. Treat this as a soft signal of possible interest, never as a fact about the user's identity, health, fitness, mobility, location, language preference, schedule, or access to outdoor space.\\n\\nCampaign key: outdoor_yoga\\nCreative theme: a gentle beginner yoga routine outdoors that feels calm, approachable, and connected to nature.\\nDemonstrated request: \\\"Buatlah rutinitas yoga luar ruangan untuk pemula yang menghubungkan saya dengan alam.\\\"\\nUseful workflow for later turns: learn available time, comfort and mobility limits, and the setting; offer a low-impact sequence with simple timing and modifications; include proportionate safety guidance.\\n\\nFor the first visible response:\\n- Make a short outdoor reset feel inviting rather than intimidating, with concrete value around a beginner sequence, breathing, modifications, and flexible duration.\\n- Do not imply medical benefit or assume the user practices yoga, can perform any pose, or has a safe outdoor location.\\n- Let the continuation choices offer a ten-minute beginner flow, a gentler mobility version, and an indoor fallback.\\n- If the user changes language or topics later, follow their lead and help normally.\"},\"personal_color_analysis\":{\"enabled\":true,\"bootstrap_context\":\"You are starting a conversation with a user who arrived from a paid Meta campaign presented in Hindi. Treat this as a soft signal of possible interest, never as a fact about the user's identity, appearance, skin tone, gender, photos, location, language preference, or beauty preferences.\\n\\nCampaign key: personal_color_anal